var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 11월 9일 런던, 화이트 채플\\n<color=#ffd34c>심야</color>","JPN":"1888年11月9日　ロンドン、ホワイトチャペル\\n<color=#ffd34c>深夜</color>","ENG":"November 9, 1888, London, White Chapel,\\n<color=#ffd34c>Midnight</color>","TWN":"1888年11月9日 倫敦，白教堂<color=#ffd34c>深夜</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"저는 이 세상이 변하길 바라거든요.","JPN":"私はこの世界が変わってほしいんです。","ENG":"Because I wish the world would change.","TWN":"我希望這個世界能夠改變。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 필요하답니다. 이 세계에 천사를 강림시키기 위한 제물이.","JPN":"だから必要なんです。この世界に天使を降臨させるための生贄が。","ENG":"That's why it's necessary. To give offerings so that an angel will descend to this world.","TWN":"所以為了讓天使降臨到這個世界，祭品是必要的——"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"당신의 가슴에 새겨진 증오스러운 <color=#ffd34c>증표</color>로써.","JPN":"あなたの胸に刻まれている憎い<color=#ffd34c>印</color>をもって。","ENG":"With that repulsive <color=#ffd34c>mark</color> that's on your chest.","TWN":"不如把銘刻在你胸前的那個憎惡<color=#ffd34c>印記</color>給我吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"……뭐?","JPN":"……えっ？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"이건, 파노라마의 거울 조각……?","JPN":"これは、パノラマの鏡の破片……？","ENG":"That's a Panorama mirror fragment...?","TWN":"這是，全景的碎片……？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다는, 말은 설마……?","JPN":"ということは、まさか……？","ENG":"Then, that means...?","TWN":"難道你是……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"믿고 싶지 않았어.","JPN":"信じたくなかった。","ENG":"I didn't want to believe it.","TWN":"我還是不想相信。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 믿지 않았기 때문에 이 역할을 수락한 건데…….","JPN":"いいえ、信じたくなかったからこそ、この役を引き受けたのに……","ENG":"No, it's because I didn't believe it that I accepted this role...","TWN":"不，就是因為我不敢相信，所以才接受了這個角色……"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말로 너였구나. 메리 제인.","JPN":"本当にあなただったのね、メリー・ジェーン。","ENG":"So, it was really you, Mary Jane.","TWN":"真的是你啊，瑪麗·珍。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 이젠 심야의 살인마라고 불러야 할까?","JPN":"いや、もう深夜の殺人鬼と呼ぶべきかな？","ENG":"Or rather, should I call you the Midnight Killer?","TWN":"不，是不是該改叫你午夜殺人魔了？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"스완 클레어……?","JPN":"スワン・クレア……？","ENG":"Swan Claire...?","TWN":"史旺·克萊爾……？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Haha.","TWN":"……呵呵。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇네. 네가 여기 있다는 건, 모든 게 정해진 <color=#ffd34c>각본</color>이라는 거겠지.","JPN":"そうね。あなたがここにいるってことは、すべてが決められた<color=#ffd34c>脚本</color>だったってことなのよね。","ENG":"Yes. And the reason you are here means that everything is according to the <color=#ffd34c>script</color>.","TWN":"沒錯。你在這裡，表示一切都是按照<color=#ffd34c>劇本</color>進行的吧。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"실수였어. 역시 그날 모리어티의 계획대로, 극장에서 널 죽였어야 했는데.","JPN":"失敗したわ。やっぱりあの日、モリアーティの計画通り、劇場であなたを殺すべきだったのよ。","ENG":"It was a mistake. I should have killed you at the theater that day, just as Moriarty planned.","TWN":"是我的失誤。果然那天應該按照莫里蒂的計畫，在劇院殺了你。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"극장이라고……?","JPN":"劇場……？","ENG":"The theater...?","TWN":"劇院……嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"후후, 상관없다니 그거 섭섭한 소리네.","JPN":"ふふ、関係ないだなんて悲しいこと言うね。","ENG":"Haha, you're upsetting me by saying that this has nothing to do with me.","TWN":"呵呵，你說無所謂，那可真讓人傷心啊。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"나는 네 전속 스태프이고, 너는 우리 극단을 대표하는 프리마돈나인걸?","JPN":"私はあなたの専属スタッフで、あなたは我が劇団を代表するプリマドンナなのよ？","ENG":"I'm your personal staff, and you're the prima donna that represents our theater.","TWN":"我是你的專屬助理，而你是我們劇團的首席女主角喔？"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭐……?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"속였다고 해도 상관없어. 기만이라고 해도 괜찮아.","JPN":"騙されたとしても構わない。欺かれたとしても大丈夫。","ENG":"Call it deceiving or fraud, I don't really care.","TWN":"就算被騙了也沒關係，就算是利用也沒關係……"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"왜냐하면 무대 위에서 너는 정말로 아름답게 빛났으니까.","JPN":"だって、舞台の上のあなたは本当に美しく輝いていたから。","ENG":"Because you were always shining so brilliantly up on stage.","TWN":"因為在舞台上的你，真的非常閃耀、非常美麗。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"그래, 마치 백조처럼.","JPN":"だって、舞台の上のあなたは本当に美しく輝いていたから。","ENG":"Yes, you were literally a swan.","TWN":"是的，就像天鵝一樣。"},"stage":{"bg":"ROOM_03","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"대체 무슨 소리를 하는 거야! 앞뒤가 하나도 안 맞아!","JPN":"何を言ってるのか意味がわからないわ！　ちゃんと説明して！","ENG":"What are you talking about? You're making no sense!","TWN":"你到底在說什麼！前後完全矛盾了啊！"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그때 너는 나를 구해주었잖아! 앞으로도 포기하지 않고 무대에 서 달라면서?","JPN":"あの時、あなたは私を助けてくれた！　これからも諦めないで舞台に立ってほしいって励んでくれた！","ENG":"You saved me that time! You said that I shouldn't give up and get on the stage.","TWN":"那時候的你救了我！還鼓勵我說以後也不要放棄，要繼續站在舞台上，對吧？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 너는 내 팬이라고 했잖아…….","JPN":"私のファンだって……言ってくれた……","ENG":"And most of all, you said that you were my fan...","TWN":"而且還說是我的粉絲……？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"거짓말이었어.","JPN":"嘘だった。","ENG":"I lied.","TWN":"那是騙你的。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭐라고?","JPN":"……嘘？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그대가 원하는 바를 해라. 그것이 곧 그대의 법이다.</color>","JPN":"<color=#ffd34c>汝の欲することを為せ、それが汝の法とならん。</color>","ENG":"<color=#ffd34c>Do what thou wilt. For it shall be thy law.</color>","TWN":"<color=#ffd34c>行汝欲行之事，此為律法之全部。</color>"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"나에게도 원하는 게 있어. 그걸 방해한다면 너라도 용서하지 않을 거야.","JPN":"私にも叶えたいことがある。それを邪魔するなら、いくらあなたでも許さない。","ENG":"I also want something. And if you interfere, I won't forgive anyone. Even you.","TWN":"我也有我想要的東西。如果有人阻礙，就算那是你，我也不會原諒。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지금이네, 왓슨!","JPN":"今だ、ワトソン！","ENG":"Now, Watson!","TWN":"現在，華生！"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L10_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"크윽!! 저격이라고……!?","JPN":"うっ！！　狙撃……！？","ENG":"Kgh!! A sniper...?!","TWN":"呃！！狙擊手……！？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"이조차도 속임수였나!","JPN":"これも罠だったのか！","ENG":"Was this also a trick?!","TWN":"又是什麼把戲！"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"메리……?","JPN":"メリー……？","ENG":"Mary...?","TWN":"瑪麗……？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"너, 그 모습은……?","JPN":"あなた、その姿は……？","ENG":"Is that the real you...?","TWN":"這……這才是你嗎……？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"저리 비켜……!","JPN":"どけっ……！","ENG":"Out of the way!","TWN":"閃開……!"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"꺄악!","JPN":"きゃあっ！","ENG":"Kyaah!","TWN":"呃咳！？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"제길, 빗맞았나!","JPN":"くそ、外れたか！","ENG":"Bollocks! Did I miss?!","TWN":"混蛋，打偏了嗎！"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 잘 맞췄어.","JPN":"いや、よくやったよ。","ENG":"No, you got her.","TWN":"不，正好命中。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"오히려 여기서 끝내면 곤란해.","JPN":"むしろここで終わられたら困るからな。","ENG":"It would've been troublesome if she died here on the spot.","TWN":"反而太准了會很麻煩。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"현장에 대기중인 모든 경관들은 듣게!","JPN":"現場で待機している全警官に告げる！","ENG":"Attention all officers waiting at the scene!","TWN":"所有在現場待命的警官聽著！"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지금 즉시 화이트 채플의 모든 거리를 봉쇄하고, 심야의 살인마의 도주로를 차단!","JPN":"今すぐホワイトチャペルのすべての道を封鎖し、深夜の殺人鬼の逃走ルートを遮断！","ENG":"Immediately block all the streets of Whitechapel and cut off the Midnight Killer's escape route!","TWN":"立即封鎖白教堂的所有街道，切斷午夜殺人魔的逃跑路線！"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"준비해둔 군견을 풀어, 범인의 피냄새를 추적하게!","JPN":"手配しておいた軍用犬を投入し、犯人の血の匂いを追跡しろ！","ENG":"Release the military dogs and let them track the culprit's blood scent!","TWN":"放出準備好的獵犬，追蹤犯人的血跡！"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모두 만전을 기하도록! 이번이 심야의 살인마를 잡을 수 있는 마지막 기회니까!","JPN":"みんな、万全を期すように！　これが深夜の殺人鬼を捕まえる最後のチャンスだ！","ENG":"Give it your all! This could be our last chance to catch the Midnight Killer!","TWN":"大家都要全力以赴！這是抓住午夜殺人魔的最後機會了！"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"자네, 지금 제정신인가?","JPN":"君、正気か？","ENG":"Hey, are you insane?","TWN":"你是認真的嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"기껏 몰아넣은 범인을 놓아주고, 군견이라고?","JPN":"せっかく追いつめた犯人を逃しておいて、軍用犬だと？","ENG":"You're letting the criminal go and releasing the hounds on her?","TWN":"好不容易快抓住的犯人，竟然要放了？再派出獵犬不是多此一舉嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 내 정신은 멀쩡하다네. 벗이여.","JPN":"もちろん、私は正気だ、旧友。","ENG":"My mind is clear as ever, my friend.","TWN":"當然，我的意識很清醒，朋友。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마는 지금껏 희생자들의 신체에 새겨진 증표를 회수하고 있었어.","JPN":"これまで深夜の殺人鬼は、犠牲者たちの体に刻まれている印を回収していた。","ENG":"The Midnight Killer has been gathering the marks of her victims.","TWN":"午夜殺人魔一直在回收受害者身體上的印記。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 말은 의식을 수행할 장소가 정해져 있고, 그간 회수한 증표가 거기 있다는 소리야.","JPN":"それはつまり、儀式を行う場所が他にあって、今まで回収してきた印がそこにあるということだ。","ENG":"That means that the location to perform the ritual is set, and all the marks will also be there.","TWN":"這表示儀式的執行地點是確定的，連同之前回收的標記也在那裡。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그것들을 완전히 제거하지 않으면, 계속 같은 사태가 발생할 거라네.","JPN":"それらを完全に除去しないかぎり、また同じ事態が繰り返されるだけだろう。","ENG":"If we don't completely remove them, the same thing will continue to happen.","TWN":"如果不徹底清除它們，同樣的事情會不斷發生。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"황금 새벽회의 잔당이 있으니 또다른 심야의 살인마가 발생할지도 모른다는 건가.","JPN":"黄金の暁団の残党がいるから、また新しい深夜の殺人鬼が現れるかもしれないということか。","ENG":"The Golden Dawn's remnants might create another Midnight Killer. Is that it?","TWN":"因為黃金黎明會的殘党，隨時可能製造出另一個午夜殺人魔。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 심야의 살인마는 거울을 가지고 있네.","JPN":"だが、深夜の殺人鬼は鏡を持っているぞ。","ENG":"But the Midnight Killer is in possession of the mirror.","TWN":"但是午夜殺人魔手裡有鏡子。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"여기서 놓아주는 건 리스크가 너무 크지 않나?","JPN":"ここで逃がすのはリスクが高すぎるではないか？","ENG":"Isn't it too much of a risk to let her go?","TWN":"在這裡放走她，風險太大了吧？"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"괜찮을 거야. 파노라마는 겉모습을 모방해 시각을 속이는 마도구지.","JPN":"問題ない。パノラマは外見を模倣して目を欺く魔道具。","ENG":"It'll be all right. Panorama is a Curio that imitates appearances for deception.","TWN":"會沒事的。全景是依靠模仿外貌來欺騙視覺的魔導具。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"피냄새까지 숨길 수는 없어.","JPN":"だから血の匂いまでは隠せない。","ENG":"But it can't disguise the scent of blood.","TWN":"它是掩蓋不了血腥味的。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 군견을? 자네 거기까지 내다보고……!","JPN":"それで軍用犬を？　君はそこまで考えて……！","ENG":"That's what the military dogs are for? You predicted this would happen...?","TWN":"所以你說要準備獵犬？竟然看得這麼遠……"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"알아들었네. 그럼 나는 먼저 녀석을 쫓도록 하지.","JPN":"わかった。じゃあ、俺は先にヤツを追うとしよう。","ENG":"I understand. Then, I'll go after her first.","TWN":"明白了。那麼我先去追那傢伙！"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"미안하네, 스완.","JPN":"すまないな、スワン。","ENG":"Apologies, Swan.","TWN":"對不起，史旺。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어쩌면 이번에는 자네에게 너무 무리한 배역을 맡긴 걸지도 모르겠군.","JPN":"今回は君に、過酷な役割を任せてしまった。","ENG":"Perhaps I did give you a risky role after all.","TWN":"或許這次我給你安排的角色太過勉強了。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내가 범인의 정체를 확신하게 된 건, 세 번째 현장에서 거울 조각을 발견했을 때였어.","JPN":"私が犯人の正体を確信したのは、三番目の現場で鏡の破片を見つけた時だった。","ENG":"I was convinced I knew who the culprit was when we found the mirror fragment at the third murder scene.","TWN":"我確定兇手的身份，是在第三案發現場看到鏡子碎片的時候。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"거울이라는 마도구에 접근할 수 있는 사람은 극장 관계자뿐이었으니까.","JPN":"鏡という魔道具に接近できる人物は劇場の関係者だけだったからな。","ENG":"The only ones who could have had access to the mirror Curio would be the theater staff.","TWN":"能夠接觸到鏡子魔導具的只有劇院相關的人員。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 거울을 가지고 있는 이상, 지금처럼 현행범으로 잡지 않으면 의미가 없었지.","JPN":"だが鏡を持っている以上、今みたいに現行犯で捕まえないと意味がなかったんだ。","ENG":"But because of the mirror, it was meaningless to catch the killer red-handed.","TWN":"因為有那面鏡子在，不當場抓住現行犯是沒有任何意義的。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"정체가 발각되더라도, 모습을 바꾸면 수사망을 쉽게 빠져나가 버리니까.","JPN":"正体がバレても、姿を変えれば簡単に捜査網から逃れられるから。","ENG":"Even if her identity was exposed, she could have changed appearances and slipped pass our investigation.","TWN":"即使身份暴露，兇手只要改變外貌就能輕易逃脫調查網。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네도 짐작했겠지만.","JPN":"君も予想していたと思うが、","ENG":"As you may have already guessed.","TWN":"你應該也猜到了。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"애초에 그자는 메리 제인 양이 아니었어.","JPN":"そもそもあの者はメリー・ジェーンじゃない。","ENG":"That person was not Mary Jane in the first place.","TWN":"那個人根本就不是瑪麗·珍。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"조사 결과, 진짜 메리 제인은 삼 년 전에 이미 실종된 사람이었다네.","JPN":"調査した結果、本物のメリー・ジェーンは三年前すでに失踪した人物だった。","ENG":"My investigation showed that the real Mary Jane went missing three years ago.","TWN":"調查結果顯示，真正的瑪麗·珍三年前就已經失蹤了。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그림자 사태가 터진 뒤, 얼마 지나지 않아서 말이야.","JPN":"シャドウ事変から間もない時期にな。","ENG":"Not long after the Shadow incident broke out.","TWN":"時間正是在暗影事件爆發後不久。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아마도 사건을 알게 된 모리어티 교수가 흥미를 느끼고 심야의 살인마를 거두었겠지.","JPN":"そして、おそらく事件について知ったモリアーティ教授が興味を持ち、深夜の殺人鬼を匿ったのだろう。","ENG":"Professor Moriarty must have taken the Midnight Killer under his wing after hearing about that incident.","TWN":"也許是莫里蒂教授找上了她，因為興趣收留了午夜殺人魔吧。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 또 한가지 알아낸 사실이 있는데…….","JPN":"そして、もう一つわかったことがあるのだが……","ENG":"Also, there is another thing I found out...","TWN":"另外還發現了一件事……"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"진짜 메리 제인은 태어날 때부터 앞이 보이지 않는 <color=#ffd34c>맹인</color>이었다고 하더군.","JPN":"本物のメリー・ジェーンは生まれつき目の見えない<color=#ffd34c>盲人</color>だったらしい。","ENG":"The real Mary Jane was <color=#ffd34c>blind</color> since birth.","TWN":"真正的瑪麗·珍從出生起就是個<color=#ffd34c>盲人</color>。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아마도 그녀가 심야의 살인마의 <color=#ffd34c>첫번째</color> 희생자였을 거야.","JPN":"おそらく彼女が深夜の殺人鬼の<color=#ffd34c>最初</color>の犠牲者だったはずだ。","ENG":"I assume that she was the <color=#ffd34c>first</color> victim to the Midnight Killer.","TWN":"她可能是午夜殺手的<color=#ffd34c>第一個</color>受害者。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 심야의 살인마가 지금껏 모은 증표는 <color=#ffd34c>다섯</color>개가 돼.","JPN":"そうすると、深夜の殺人鬼が今まで集めた印は<color=#ffd34c>5つ</color>になる。","ENG":"Then, the number of marks the killer has collected becomes <color=#ffd34c>five</color>.","TWN":"如此一來，午夜殺人魔至今為止收集的標記已經有<color=#ffd34c>五</color>個了。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"알고 있어요.","JPN":"知ってます。","ENG":"I know.","TWN":"我知道。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저, 그 여자를 알고 있어요.","JPN":"私、あの女を知ってます。","ENG":"I know who that woman is.","TWN":"我知道那個女人。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"틀림없이 제 기억 속에 있어요. ","JPN":"確かに私の記憶の中にいるんです。 ","ENG":"She's definitely in my memory.","TWN":"沒錯，我記得很清楚。"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그 여자는…….","JPN":"あの女は……","ENG":"That woman is...","TWN":"她是……"},"stage":{"bg":"BACKSTREET","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"하아, 하아, 하아…….!","JPN":"ハア、ハア、ハア……！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"모든 것을 마무리 지어야만 해. 그 아이를 다시 보기 위해서라면…….","JPN":"すべてを終わらせないと。あの子にまた会うためなら……","ENG":"All must be finished. To see her again...","TWN":"必須結束這一切。為了再次見到那個孩子……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"이 땅에 천사를 불러들이기 위한 마지막 제물을…….","JPN":"この地に天使を呼び出す最後の生贄を……","ENG":"To summon an angel to this earth... The last sacrifice...","TWN":"召喚天使降臨這片土地的最後祭品……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"거기까지야. 심야의 살인마.","JPN":"そこまでだ。深夜の殺人鬼。","ENG":"It's the end of the line, Midnight Killer.","TWN":"到此為止了，午夜殺人魔。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 포위되었어.","JPN":"君は包囲された。","ENG":"You're surrounded.","TWN":"你已經被包圍了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"허튼 수작은 부리지 않는 게 좋을 거야.","JPN":"余計な真似はしないほうがいい。","ENG":"And don't try any funny business.","TWN":"最好不要耍花招。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"흉기는 발견되지 않았지만, 심야의 살인마의 수법은 날카로운 금속 날붙이에 의한 척살.","JPN":"凶器は発見されてないが、深夜の殺人鬼の手口は鋭い刃物による刺殺。","ENG":"The murder weapon was never found, but the Midnight Killer's M.O. was using a sharp metal blade.","TWN":"雖然沒有發現兇器，但午夜殺人魔的手法是用鋒利的金屬刀具進行刺殺。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그 흉터는 크기와 모양이 일정하지 않고 모두 제각각이었지.","JPN":"だがその傷跡は一定の大きさや形ではなく、みんなバラバラだった。","ENG":"However, the scars' size and shape were all different.","TWN":"受害者身上的那些傷痕大小和形狀都不一致。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다시 말해, 그건 일정한 형태를 가진 날붙이가 아니었다는 것.","JPN":"つまり、それは一定の形の刃物ではないということ。","ENG":"In other words, it wasn't a blade with a certain shape.","TWN":"也就是說，作案刀具並沒有固定的形態。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"역시 가장 쉽게 생각해 볼 수 있는 케이스는.","JPN":"考えられるケースの一つとしては……","ENG":"The easiest case to think of is...","TWN":"果然，最容易想到的情況是。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 <color=#ffd34c>금속</color>을 조작하는 능력을 보유한 이능력자라는 거겠지.","JPN":"君が<color=#ffd34c>金属</color>を操作する能力を持った異能力者であるということだろう。","ENG":"that you are a Supernatural with the ability to manipulate <color=#ffd34c>metal</color>.","TWN":"你是擁有<color=#ffd34c>金屬</color>操控能力的超能力者吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 자리에 있는 모든 경관은 자네만을 위해, 특별히 제작한 마석탄으로 무장하고 있네.","JPN":"この場にいるすべての警官は君用に、特別に製作された魔石弾で武装している。","ENG":"All the officers here are armed with Mana bullets especially made for you.","TWN":"在場的所有警官都為你特別裝備了用魔石彈製作的武器。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"탄두가 금속이 아니기 때문에 총탄의 궤적을 조작하는 건 불가능 해.","JPN":"弾頭が金属ではないため、銃弾の軌道を操作することはできない。","ENG":"It'll be impossible for you to curve the trajectory of the bullet as the bullets are not made of metal.","TWN":"因為彈頭不是金屬的，所以你無法操控子彈的軌跡。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"얌전히 포기하게. 심야의 살인마.","JPN":"大人しく諦めたまえ。深夜の殺人鬼。","ENG":"Surrender, Midnight Killer.","TWN":"乖乖放棄吧。午夜殺人魔。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 노리고 있던 마지막 희생자, 안젤리나 터너는 스코틀랜드 야드가 보호 중이야.","JPN":"君が狙っていた最後の犠牲者、アンジェリーナ・ターナーはスコットランドヤードが保護している。","ENG":"The last victim you are after, Angelina Turner is in safe hands of the Scotland Yard.","TWN":"你盯上的最後一個犧牲者，安潔莉娜·特納，正在蘇格蘭場的保護之下。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다시 말해, 자네는 절대 이 의식을 성공시킬 수 없다는 뜻이지.","JPN":"つまり、君は絶対この儀式を成功させることができないということだ。","ENG":"In short, you will never be able to complete this ritual.","TWN":"換句話說，你絕對不可能成功完成這個儀式。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그렇군. 이 모든 건 당신이 짠 각본이었나?","JPN":"そうか。このすべてはあんたが書き上げた脚本だったのか？","ENG":"I see. Did you scheme all of this?","TWN":"原來如此，這一切都是你策劃的劇本嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그 여자의 증표를 노릴 지 알고 있었다는 건, 다시 말해 메시지를 파악했다는 뜻이겠지.","JPN":"あの女の印を狙うと知っていたということは、つまりメッセージを把握したということだろう。","ENG":"Seeing how you know, I was after that girl's mark can only mean that you figured out what the messages meant.","TWN":"知道她會被盯上，是因為你已經充分理解了塗鴉的資訊。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모리어티 교수의 수법은 너무나 잘 알고 있으니까.","JPN":"モリアーティ教授の手口はとてもよくわかっているからな。","ENG":"I know too well of Professor Moriarty's methods.","TWN":"因為我對莫里蒂教授的手法太了解了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아마도 메시지를 남기는 행위 자체가 의식에 필요한 연출이었을 거야.","JPN":"おそらくメッセージを残す行動自体が儀式に必要な演出だったのだろう。","ENG":"The messages left behind were an act in itself necessary for the ritual.","TWN":"或許留下資訊本身就是儀式所需的演出。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"의식이 제대로 성사되기 위해서는 집단 무의식으로부터 발현된 힘이 필요 했겠지.","JPN":"儀式をちゃんと成立させるためには、集合的無意識から発現した力が必要だったはずだ。","ENG":"For the ritual to succeed, you needed the power manifested by the collective unconsciousness.","TWN":"為了順利完成儀式，必定需要從集體無意識中汲取力量。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>심야의 살인마라는 존재가 불가사의한 범죄를 저지르고 있다.</color>","JPN":"<color=#ffd34c>深夜の殺人鬼という存在が、不可思議な犯罪を犯している。</color>","ENG":"<color=#ffd34c>The Midnight Killer is committing mysterious crimes throughout.</color>","TWN":"<color=#ffd34c>午夜殺人魔正在犯下神秘的罪行。</color>"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"런던의 모든 시민들에게 그런 공포감을 심어줄 필요가 있던 거지.","JPN":"ロンドンの全市民にそのような恐怖を与える必要があったんだ。","ENG":"You needed to instill fear into the minds of London's citizens.","TWN":"有必要讓倫敦的所有市民都感受到那種恐懼。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그렇다고 해서 무의미한 메시지는 쓰지 않았을 거야.","JPN":"だが、だとして無意味なメッセージは残さなかったはずだ。","ENG":"Even so, the messages weren't entirely meaningless.","TWN":"但即便如此，也不會發送毫無意義的資訊。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"왜냐하면, 이 의식에는 나름의 절차가 중요했을 테니까.","JPN":"なぜなら、この儀式ではそれなりの手順が大事なはずだから。","ENG":"Because the process was rather important for the ritual.","TWN":"因為這個過程對儀式來說相當重要。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군요!","JPN":"そうだったのね！","ENG":"I get it now!","TWN":"原來如此！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 낙서는 어떠한 <color=#ffd34c>절차</color>를 뜻하고 있는 거예요.","JPN":"あの落書きは、何かの<color=#ffd34c>手順</color>を表してるんです。","ENG":"Those writings refer to a certain <color=#ffd34c>process</color>.","TWN":"這些塗鴉暗示了某種<color=#ffd34c>程序</color>！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마는 정해진 절차에 따라 희생자들의 증표를 회수하고 있는 거죠.","JPN":"深夜の殺人鬼は決められた手順に従って……犠牲者たちの印を回収してる。そういうことですね？","ENG":"The Midnight Killer is collecting the marks of his victims according to a certain order.","TWN":"午夜殺人魔正在按照既定程序回收受害者的標記！"},"stage":{"bg":"BACKSTREET3","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 그 절차라는 게 대체 뭐죠?","JPN":"じゃあ、その手順っていったい何ですか？","ENG":"So, what is this process?","TWN":"那麼，所謂的程序到底是什麼？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"간단한 이야기라네, 스완.","JPN":"簡単な話だよ、スワン。","ENG":"It's elementary, my dear Swan.","TWN":"這是很簡單的推理，親愛的史旺。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스. 이 의식은 <color=#ffd34c>황금으로 향하는 순례</color>라고 할 수 있어.","JPN":"マグヌム・オプス。この儀式は<color=#ffd34c>黄金へ向かう巡礼</color>だと言える。","ENG":"Magnum Opus. This ritual is a <color=#ffd34c>pilgrimage to gold</color>.","TWN":"偉大傑作，這個儀式又被稱為<color=#ffd34c>通往黃金的朝聖</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"황금으로 향하는 순례……?","JPN":"黄金へ向かう巡礼……？","ENG":"A pilgrimage to gold...?","TWN":"通往黃金的朝聖……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"옛 현인들은 이 세상이 만들어진 원리를 알아내기 위해 수많은 시도와 노력을 해왔지.","JPN":"古くから知識人たちは、この世界が作られた原理を解明するために、たくさんの試みと努力をしてきた。","ENG":"The sages of old made numerous attempts to find out the principles of how this world was created.","TWN":"古代賢者們為了揭示這個世界的構造原理，進行了無數次嘗試和努力。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세상의 모든 것과 연결된, 그 보이지 않는 실을 규명해내기 위해서.","JPN":"この世界のすべてと繋がった、その見えない糸を明らかにするために。","ENG":"To uncover the invisible thread that connects everything in this world.","TWN":"為了探明與這個世界萬物相連的那條無形之線。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"연금술 역시 마찬가지야. 표면적으로는 쓸모 없는 금속을 금으로 바꾸는 기술이었지만.","JPN":"錬金術もまた同じだ。表面的には使えない金属を金に変える技術だったのだが、","ENG":"Alchemy is the same. It was a technique to transform useless metal into gold on the surface.","TWN":"煉金術也是一樣的。雖然表面上看是將無用的金屬變成金子的技術。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 내면에는 인간의 영혼을 불멸하게…….","JPN":"その裏には、人間の魂を不滅にする……","ENG":"However, the real goal was for the human soul to become immortal...","TWN":"但真正的目的是將人類的靈魂變為不朽……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다시 말해, 신적 존재로 탈바꿈하는 기술을 뜻하기도 하지.","JPN":"つまり、神的存在に変える技術を意味したりもする。","ENG":"Simply put, it meant a technique to transform into a divine being.","TWN":"換句話說，這是一項意指變為神之存在的技術。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"신적 존재라는 건 설마……?","JPN":"神的存在って、まさか……？","ENG":"And by divine being, you mean...?","TWN":"所謂的神明難道是……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그녀가 첫 번째 시련을 지나, 내게 오게 하노라. 그녀는 <color=#ffd34c>은</color>과 같이 되리라.","JPN":"彼女が一つ目の試練を越え、私へと向かわせる。彼女は<color=#ffd34c>銀</color>のようになるだろう。","ENG":"Let her come through the first ordeal to me. And she will be as <color=#ffd34c>silver</color>.","TWN":"讓她經歷第一之裁判吧。來到我面前，她將如<color=#ffd34c>銀</color>一般純淨。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"두 번째 시련을 지나라. 그녀는 <color=#ffd34c>납</color>과 같이 견고해지리라.","JPN":"二つ目の試練を越えろ。彼女は<color=#ffd34c>鉛</color>のように堅固になるだろう。","ENG":"Go through the second ordeal. For she will be sturdy like <color=#ffd34c>lead</color>.","TWN":"經歷第二之裁判。她將堅固如<color=#ffd34c>鉛</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"세 번째 시련을 지나라. 그녀는 녹슬지 않는 <color=#ffd34c>주석</color>과 같이 될지니.","JPN":"三つ目の試練を越えろ。彼女は錆びない<color=#ffd34c>錫</color>のようになるだろう。","ENG":"Pass the third ordeal, for she will become like <color=#ffd34c>tin</color> that does not rust.","TWN":"經歷第三之裁判，她將如不鏽的<color=#ffd34c>錫</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"네 번째 시련을 지나라. 그녀는 불꽃에 달궈진 <color=#ffd34c>철</color>이 될지니.","JPN":"四つ目の試練を越えろ、彼女は炎で煉られた<color=#ffd34c>鉄</color>になるだろう。","ENG":"Pass the fourth ordeal, and she will become <color=#ffd34c>iron</color> heated in flame.","TWN":"經歷第四之裁判，她將會是淬火的<color=#ffd34c>鐵</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고…… 마지막은 <color=#ffd34c>금</color>이었겠지.","JPN":"そして……最後は<color=#ffd34c>金</color>だったはずだ。","ENG":"And... the last would be <color=#ffd34c>gold</color>.","TWN":"以及……最後一個，<color=#ffd34c>金</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇지 않나, 심야의 살인마?","JPN":"違うか？　深夜の殺人鬼。","ENG":"Isn't that right, Midnight Killer?","TWN":"對吧，午夜殺人魔？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐만요, 애버라인.","JPN":"ちょっと待ってください、アバーライン。","ENG":"Hold on, Abberline.","TWN":"等等，艾伯林。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마의 의식이 어떤 연금술을 행하려 했다는 건 알겠어요.","JPN":"深夜の殺人鬼が儀式を通して、何かの錬金術を行おうとしていたということはわかりました。","ENG":"I get that the Midnight Killer was performing some kind of alchemy ritual.","TWN":"我明白午夜殺人魔的儀式是為了進行某種煉金術。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 이것만으로는 희생자들 간에 연결점이 부족하지 않나요?","JPN":"でも、これだけでは犠牲者たちの繋がりが弱いんじゃないんですか？","ENG":"But that alone lacks a correlation with the victims, doesn't it?","TWN":"但是僅憑這些，受害者之間的聯繫是不是有點不足？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마에게 마지막으로 노려졌던 안젤리나가 어째서 금이 되는 거죠?","JPN":"深夜の殺人鬼に最後に狙われていたアンジェリーナが、どうして金になるんですか？","ENG":"How could Angelina, who was targeted as the last victim, be gold?","TWN":"為什麼最後被盯上的安潔莉娜會是金呢？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"말하지 않았나, 스완.","JPN":"言ったではないか、スワン。","ENG":"Didn't I say, Swan?","TWN":"我不是說過嗎，史旺。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세상의 모든 것은 보이지 않는 실로 연결되어 있다고.","JPN":"この世のすべては見えない糸で繋がっていると。","ENG":"This world is connected by invisible threads.","TWN":"這個世界上的一切都被看不見的絲線連著。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"인간의 영혼은 금속이 아니야. 그건 어디까지나 상징이지.","JPN":"人間の魂は金属ではない。これはあくまで象徴だ。","ENG":"The human soul is not metal. That is just a symbol.","TWN":"人類的靈魂不是金屬。那只是一個象徵。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"따라서 심야의 살인마가 저지른 의식의 절차는 고전 점성술에 근거를 두고 있어.","JPN":"よって、深夜の殺人鬼が行った儀式の手順は古典の占星術に基づいている。","ENG":"Accordingly, the Midnight Killer's ritual procedures are based on classical astrology.","TWN":"因此，午夜殺人魔是基於古典占星術來進行儀式程式的。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"점성술이라고요?","JPN":"占星術？","ENG":"Astrology?","TWN":"占星術嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"점성술에서는 육안으로 관측할 수 있는 일곱 개의 천체를 중요하게 생각한다네.","JPN":"占星術では肉眼で観測できる7つの天体を重要視している。","ENG":"Astrology emphasized the seven celestial bodies that couldn't be observed by the naked eye.","TWN":"在古典占星術中，人們極其重視肉眼可見的七大天體。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이를 테면, 하늘이라는 무대에서 각각의 천체는 등장인물과 같지.","JPN":"空という舞台において、それぞれの天体はいわば登場人物に等しい。","ENG":"For instance, if the sky is the stage, each celestial body is like a character.","TWN":"比如說，在天空這個舞台上，每個天體就像是登場的人物。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 등장인물을 공전주기가 긴 순서로 나열하면…….","JPN":"その登場人物を公転周期が長い順で並べると……","ENG":"If you sort them in order of their longest orbital period...","TWN":"如果按照觀察到的運行快慢和軌道長短來排列這些登場人物的話……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"토성, 목성, 화성, 태양, 금성, 수성 그리고 달의 순서가 된다네.","JPN":"土星、木星、火星、太陽、金星、水星、そして月の順番になる。","ENG":"you get Saturn, Jupiter, Mars, Sun, Venus, Mercury, and the Moon.","TWN":"就會得到土星、木星、火星、太陽、金星、水星和月亮這樣的排列……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 순서의 반복을 점성술에서는 <color=#ffd34c>칼데안 오더</color>라고 불러.","JPN":"この順番の繰り返しを占星術では<color=#ffd34c>カルディアン・オーダー</color>と呼ぶ。","ENG":"The repetition of this order is called the <color=#ffd34c>Chaldean Order</color> in astrology.","TWN":"這種順序在古典占星學中被稱為<color=#ffd34c>迦勒底星序</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아, 그렇지! 태양과 달이 행성이 아니라는 것쯤은 나도 알고 있어, 왓슨.","JPN":"あ、もちろん！　太陽と月が惑星ではないということくらいは私も知っているぞ、ワトソン。","ENG":"Oh, right! I know that the sun and moon are not planets, Watson.","TWN":"噢，對了！我當然知道太陽和月亮不是行星，華生。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지동설 정도는 당연한 상식 아닌가? 이건 어디까지나 점성술에서의 이야기라네.","JPN":"地動説くらいは当然の常識ではないか。これはあくまで占星術での話だ。","ENG":"The heliocentric theory is common sense. This is about astrology.","TWN":"日心說這種常識我當然是知道的。但以上所說的都是古典占星術中的看法。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"자네, 왜 갑자기 날 보고 그런 얘기를 하나?","JPN":"君、どうしていきなり俺にそんなことを言うんだ？","ENG":"Hey, why are you looking at me and saying that?","TWN":"呃，你為什麼突然看著我說這種話？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"크흠……! ","JPN":"ゴホン……！ ","ENG":"Ahem...!","TWN":"咳咳……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어쨌든 연금술에서 이 행성들은 각각의 고유한 금속으로도 표현되지.","JPN":"とにかく、錬金術でこの惑星たちはそれぞれ固有の金属でも表現されいる。","ENG":"Anyway, each planet is represented with its own metals.","TWN":"無論如何，在煉金術中，這些行星各自也代表著獨特的金屬。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 금속은 각각 납, 주석, 철, 금, 황동, 수은 그리고 은이라네.","JPN":"その金属とはすなわち、鉛、錫、鉄、金、黄銅、水銀、そして銀だ。","ENG":"And in order, it is lead, tin, iron, gold, brass, mercury, and silver.","TWN":"分別是……鉛、錫、鐵、金、黃銅、水銀和銀。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"메시지에 쓰여 있던 금속……!","JPN":"メッセージに書かれてた金属……！","ENG":"The metals written in the messages...!","TWN":"這些是塗鴉中提到的金屬……!"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"또한 점성술에서는 인체를 하나의 축소된 소우주라고 보기도 해.","JPN":"また、占星術では人体を一つの縮小された小宇宙だとも見ている。","ENG":"Also, astrology sees the human body as a miniature microcosm.","TWN":"此外，在占星術中，人的身體也被視為一個縮小的微型宇宙。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"따라서 각 신체 일부는 대응되는 천체의 영향을 강하게 받는다고 할 수 있어.","JPN":"だから体の各パーツはそれに対応する天体の影響を強く受けているとも言えるさ。","ENG":"So, it can be said that each body part is strongly influenced by the corresponding celestial body.","TWN":"因此，可以說每個身體部位都會強烈地受到對應天體的影響。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"신체의 일부라고요? 설마……?","JPN":"体の各パーツ？　まさか……？","ENG":"Body parts? Then...?","TWN":"身體的一部分？不會吧……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래. 이를 테면, 달의 영향력을 받는 신체 부위는 가슴. 즉, 흉부라네.","JPN":"ああ。例えば、月の影響力を受ける身体部位は胸。つまり、胸部だ。","ENG":"Yes. For example, the moon's influence is the chest.","TWN":"是。比方說，受月亮影響的身體部位是胸部。也就是胸腔。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 첫번째 희생자라고 알려진 마리는 <color=#ffd34c>흉부</color>에 증표가 있었어.","JPN":"そして最初の犠牲者として知られているマリーは<color=#ffd34c>胸部</color>に印があった。","ENG":"Also, the first victim, Mary, had a mark on her <color=#ffd34c>chest</color>.","TWN":"對應的，第一個受害者瑪麗的超能力者標記在<color=#ffd34c>胸口</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그녀의 탄생일은 6월 30일. <color=#ffd34c>게자리</color>라네.","JPN":"彼女の誕生日は6月30日。<color=#ffd34c>かに座</color>だ。","ENG":"She was born on June 30, a <color=#ffd34c>Cancer</color>.","TWN":"她的生日是6月30日。<color=#ffd34c>巨蟹座</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"게자리의 수호성은 <color=#ffd34c>달</color>. 달의 고유 금속은 <color=#ffd34c>은</color>이지.","JPN":"かに座の守護星は<color=#ffd34c>月</color>。月の固有金属は<color=#ffd34c>銀</color>だ。","ENG":"Cancer's ruling celestial body is the <color=#ffd34c>moon</color>. And the moon's unique metal is <color=#ffd34c>silver</color>.","TWN":"巨蟹座的守護星是<color=#ffd34c>月亮</color>。而月亮所代表的金屬是<color=#ffd34c>銀</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그녀가 첫 번째 시련을 지나, 내게 오게 하노라. 그녀는 <color=#ffd34c>은</color>과 같이 되리라…….","JPN":"彼女が一つ目の試練を越え、私へと向かわせる。彼女は<color=#ffd34c>銀</color>のようになるだろう……","ENG":"Let her come through the first ordeal to me. And she will be as <color=#ffd34c>silver</color>...","TWN":"讓她經歷第一之裁判吧。來到我面前，她將如<color=#ffd34c>銀</color>一般……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 메시지의 메타포는 행성의 고유 금속과 그에 해당하는 신체 일부였군요.","JPN":"じゃあ、メッセージのメタファーは惑星の固有金属とそれに該当する体のパーツだったんですね。","ENG":"Then, the metaphor in the message was referring to the planet's unique metal and the corresponding body part.","TWN":"所以，塗鴉的隱喻是行星代表的金屬和相應的身體部位啊。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"두번째 희생자 허니 채프먼은 우측 <color=#ffd34c>무릎</color>에 증표가 있었어.","JPN":"二番目の犠牲者、ハニー・チャップマンは右側の<color=#ffd34c>膝</color>に印があった。","ENG":"The second victim, Honey Chapman, had a mark on her right <color=#ffd34c>knee</color>.","TWN":"第二個受害者哈妮·查普曼的標記在右<color=#ffd34c>膝蓋</color>上。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그녀의 탄생일은 1월 23일. <color=#ffd34c>물병자리</color>.","JPN":"彼女の誕生日は1月23日。<color=#ffd34c>水瓶座</color>。","ENG":"She was born on January 23, an <color=#ffd34c>Aquarius</color>.","TWN":"……生日是1月23日。<color=#ffd34c>水瓶座</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"수호성은 <color=#ffd34c>토성</color>. 금속은 <color=#ffd34c>납</color>이지.","JPN":"守護星は<color=#ffd34c>土星</color>。金属は<color=#ffd34c>鉛</color>だ。","ENG":"The ruling planet is <color=#ffd34c>Saturn</color>, and the metal is <color=#ffd34c>lead</color>.","TWN":"……守護星是<color=#ffd34c>土星</color>。金屬是<color=#ffd34c>鉛</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"세 번째, 네 번째 희생자도 마찬가지야.","JPN":"三番目、四番目の犠牲者もまた同じだよ。","ENG":"The third and fourth victims are the same.","TWN":"第三個，第四個犧牲者也是一樣。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"각각 증표는 좌측 <color=#ffd34c>대퇴부</color>와 <color=#ffd34c>후두</color>에 있었지.","JPN":"それぞれの印は左側の<color=#ffd34c>大腿部</color>と<color=#ffd34c>後頭部</color>にあった。","ENG":"Each had a mark on her left <color=#ffd34c>thigh</color> and <color=#ffd34c>voice box</color> respectively.","TWN":"每個標記分別在左側<color=#ffd34c>大腿</color>和<color=#ffd34c>喉部</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 <color=#ffd34c>사수자리</color>와 <color=#ffd34c>양자리</color>.","JPN":"それから、<color=#ffd34c>射手座</color>と<color=#ffd34c>牡羊座</color>。","ENG":"And they were a <color=#ffd34c>Sagittarius</color> and <color=#ffd34c>Aries</color>.","TWN":"對應了<color=#ffd34c>射手座</color>和<color=#ffd34c>白羊座</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"수호성은 <color=#ffd34c>목성</color>과 <color=#ffd34c>화성</color>. 금속은 <color=#ffd34c>주석</color>과 <color=#ffd34c>철</color>이라네.","JPN":"守護星は<color=#ffd34c>木星</color>と<color=#ffd34c>火星</color>。金属は<color=#ffd34c>錫</color>と<color=#ffd34c>鉄</color>だ。","ENG":"The ruling planets are <color=#ffd34c>Jupiter</color> and <color=#ffd34c>Mars</color>, with metals <color=#ffd34c>tin</color> and <color=#ffd34c>iron</color>.","TWN":"守護星是<color=#ffd34c>木星</color>和<color=#ffd34c>火星</color>。金屬是<color=#ffd34c>錫</color>和<color=#ffd34c>鐵</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 자네가 노리던 마지막 희생자는…….","JPN":"そして君が狙っていた最後の犠牲者は……","ENG":"And for the last victim you were after...","TWN":"而你瞄準的最後一個犧牲者……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"<color=#ffd34c>흉부</color>에 증표가 있지.","JPN":"<color=#ffd34c>胸部</color>に印がある。","ENG":"She has a mark on her <color=#ffd34c>chest</color>.","TWN":"<color=#ffd34c>胸部</color>有標記。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"태양에 대응되는 신체는 심장. 별자리는 <color=#ffd34c>사자자리</color>였고.","JPN":"太陽に対応する体のパーツは心臓。星座は<color=#ffd34c>獅子座</color>で、","ENG":"The body corresponding to the sun is the heart. Her constellation was <color=#ffd34c>Leo</color>.","TWN":"對應著太陽的身體部位是心臟。星座是<color=#ffd34c>獅子座</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그리고…… <color=#ffd34c>금</color>이야.","JPN":"そして……<color=#ffd34c>金</color>だ。","ENG":"Also... <color=#ffd34c>gold</color>.","TWN":"主宰的金屬是…… <color=#ffd34c>金</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"……그래.","JPN":"……ああ。","ENG":"...Yes.","TWN":"……沒錯。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 가장 먼저 저지른 살인, 메리 제인은 실종처리 되어 확인할 방도가 없지만.","JPN":"君が最初に犯した殺人、メリー・ジェーンは失踪処理されて確認する術はないが、","ENG":"For the first murder you committed, Mary Jane is listed as missing, so there's no way to confirm.","TWN":"至於你最初犯下的那起謀殺，瑪麗·珍被處理為失蹤，無法確認。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그녀가 있었던 시설을 통해, 생일 정도는 알 수 있었지.","JPN":"彼女がいた施設を通じて、誕生日くらいは知ることができた。","ENG":"But through the facility she grew up in, I was able to find out her birthday.","TWN":"通過她以前的記錄，可以知道她的生日。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"생일은 6월 3일. 별자리는 <color=#ffd34c>쌍둥이 자리</color>.","JPN":"誕生日は6月3日。星座は<color=#ffd34c>双子座</color>。","ENG":"Born on June 3, a <color=#ffd34c>Gemini</color>.","TWN":"6月3日。星座是<color=#ffd34c>雙子座</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"수호성은 <color=#ffd34c>수성</color>. 금속은 <color=#ffd34c>수은</color>이지.","JPN":"守護星は<color=#ffd34c>水星</color>。金属は<color=#ffd34c>水銀</color>だ。","ENG":"The ruling planet is <color=#ffd34c>Mercury</color>, and its metal is also <color=#ffd34c>mercury</color>.","TWN":"守護星是<color=#ffd34c>水星</color>。金屬是<color=#ffd34c>水銀</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"……그녀의 증표 역시 <color=#ffd34c>흉부</color>에 있었어.","JPN":"……彼女の印もまた<color=#ffd34c>胸部</color>にあった。","ENG":"...She had a mark on her <color=#ffd34c>chest</color>.","TWN":"……她的標記也在<color=#ffd34c>胸部</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"수성이 영향을 끼치는 신체는 목 바로 아래의 기관이니까.","JPN":"水星の影響を受ける体のパーツは、首の真下にある器官だからな。","ENG":"Because the body part that Mercury influences is the one right below the neck.","TWN":"水星影響的身體部位是脖子正下方的器官。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"토성, 목성, 화성, 태양, 금성, 수성, 달 그리고 다시 토성, 목성, 화성 태양…….","JPN":"土星、木星、火星、太陽、金星、水星、月。そしてまた土星、木星、火星、太陽……","ENG":"Saturn, Jupiter, Mars, Sun, Venus, Mercury, and the Moon. Then again, Saturn, Jupiter, Mars, Sun...","TWN":"土星，木星，火星，太陽，金星，水星，月亮，然後又是土星，木星，火星，太陽……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"천체의 공전주기에 따른 칼데안 오더는 정해진 순서는 반복하지.","JPN":"天体の公転周期によるカルディアン・オーダーは決められた順番を繰り返す。","ENG":"The Chaldean Order follows the orbital period and repeats itself.","TWN":"根據古代人們所觀測到的天體運行週期，迦勒底星序重複著固定的順序。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"점성술에 따르면, <color=#ffd34c>수성</color>에서 <color=#ffd34c>태양</color>까지.","JPN":"占星術によると、<color=#ffd34c>水星</color>から<color=#ffd34c>太陽</color>まで。","ENG":"In astrology, from <color=#ffd34c>Mercury</color> to the <color=#ffd34c>Sun</color>.","TWN":"根據占星術，從<color=#ffd34c>水星</color>到<color=#ffd34c>太陽</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"연금술에 따르면, <color=#ffd34c>수은</color>에서 <color=#ffd34c>금</color>에 이르기까지.","JPN":"錬金術によると、<color=#ffd34c>水銀</color>から<color=#ffd34c>金</color>にいたるまで、","ENG":"In alchemy, from <color=#ffd34c>silver</color> to <color=#ffd34c>gold</color>.","TWN":"根據煉金術，從<color=#ffd34c>水銀</color>到<color=#ffd34c>金</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 <color=#ffd34c>어떤 존재</color>를 불러들이기 위해, 순례를 하고 있었던 거야.","JPN":"君は<color=#ffd34c>ある存在</color>を呼び出すために、巡礼をしていたんだ。","ENG":"You were on a pilgrimage to summon a <color=#ffd34c>certain being</color>.","TWN":"你為了召喚<color=#ffd34c>某種存在</color>，一直在進行朝聖。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>어떤 인과</color> 관계로 이어진 이들을 살해하고, 그들의 증표를 제물로 바침으로써 말이지.","JPN":"<color=#ffd34c>とある因果</color>関係で繋がっている者たちを殺し、彼らの印を生贄として捧げてな。","ENG":"By murdering the victims with whom there was a <color=#ffd34c>certain causality</color> and offering their marks as sacrifice.","TWN":"通過殺死與<color=#ffd34c>某種因果</color>關係相連的人物，並將他們的信物作為祭品。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"당신, 역시 대단하네.","JPN":"あんた、やっぱりすごいな。","ENG":"You are incredible.","TWN":"你果然很厲害呢。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"아무것도 모르는 상태에서 거기까지 맞추다니.","JPN":"何も知らない状態からここまでたどり着くなんて。","ENG":"Being able to guess that much without knowing anything.","TWN":"在什麼都不知道的情況下，竟然能推測到這一步。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아마도 삼 년 전의 첫 번째 살인은 자네의 단독 범행이었겠지.","JPN":"おそらく三年前、初めて犯した殺人は、君の単独犯行だったんだろう。","ENG":"I assume that your first murder from three years ago was probably done alone.","TWN":"或許三年前的第一次殺人是你的單獨行動。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 뒤에 일련의 살인이 의식으로 작용하기 시작한 건, 두 번째 살인부터였을 거야.","JPN":"その後に一連の殺人が儀式になり始めたのは、二番目の殺人からのはずだ。","ENG":"After the second murder, the serial killings started to serve as the ritual.","TWN":"而之後的一系列伴隨著儀式的連環謀殺，應該是從你第二次殺人開始。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네의 공범자 모리어티 교수에 의해서 말이지.","JPN":"君の共犯、モリアーティ教授によってね。","ENG":"By your accomplice, Professor Moriarty.","TWN":"在你遇到共犯莫里蒂教授之後幹的。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"맞아. 삼 년 전, 그 아이를 잃고 나서 나는 어떤 계시를 받았거든.","JPN":"ああ。三年前、あの子を失ってから私はとある啓示を受けた。","ENG":"You're right. Three years ago, I had a calling after I lost her.","TWN":"沒錯。三年前失去那個孩子之後，我得到了某種啟示。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"매일 같이 잠들 기 전, 머릿속에 속삭임이 들려왔지.","JPN":"毎日眠りにつく前、何者かが私の脳裏に囁いてきたのさ。","ENG":"Every night before going to sleep, I could hear a whisper in my head.","TWN":"每天入睡前，我的腦海中都會響起低語。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"이 세계에 뿌려진 여섯 개의 증오스러운 증표를 바치면, 다시 만날 수 있을 거라고.","JPN":"この世界に振り撒かれた六つの憎い印を捧げれば、また会えるって。","ENG":"That I could meet her again if I offered the six dreaded marks scattered throughout this world.","TWN":"如果獻上散佈在這個世界上的六個憎恨之印，就能再次與 她相見了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"계시라고?","JPN":"啓示だと？","ENG":"A calling?","TWN":"啟示？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그래, 모리어티는 그게 천사라고 했어. 하지만 그게 무엇이든 중요하지 않아.","JPN":"ああ、モリアーティはそれが天使って言っていた。だけど、それが何なのかは重要じゃない。","ENG":"Yes, Moriarty said that it was an angel. But it didn't matter who or what it was.","TWN":"是的，莫里蒂說那是天使。但我覺得並不重要。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"이 썩어빠진 세상을 부수고, 다시 창조해낼 힘을 가지고 있다면 나에겐 그게 천사니까.","JPN":"この腐った世界を壊して、作り直す力を持っているなら。私にとってはそれこそが天使だから。","ENG":"For anything that has the power to burn down this retched world and recreated it, it will be an angel to me.","TWN":"如果有任何力量可以摧毀這個腐朽的世界，並重新創造它，對我來說那個就是天使。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저, 당신을 기억하고 있어요.","JPN":"私、あなたのことを覚えています。","ENG":"I remember you.","TWN":"我記得你。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"매일 같이 극장 앞 거리에서 초상화를 그리던 분이었죠? 항상 동생과 함께였고.","JPN":"毎日劇場前の通りで肖像画を描いてた方ですよね？　いつも妹さんと一緒にいて。","ENG":"You're the one who painted portraits in front of the theater every day, right? You were always with your little sister.","TWN":"你是那個總是和妹妹在一起，每天都在劇院前的街道上畫肖像畫的人吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALEISTER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"많이 팔리지는 않았지만, 저 당신의 그림을 좋아했어요.","JPN":"売れ行きはあまりよくなかったけど、私はあなたの絵が好きでした。","ENG":"Though they didn't sell well, I like your paintings.","TWN":"雖然賣得不多，但我很喜歡你的畫。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신도 저를 기억하시죠?","JPN":"あなたも私のことを覚えてるでしょう？","ENG":"Do you remember me as well?","TWN":"你也記得我吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"카넬리안…….","JPN":"カーネリアン……","ENG":"Carnelian...?","TWN":"卡內利安……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그 이름. 너무나 오랜만에 다시 듣는 것 같네.","JPN":"その名前。本当に久しぶりに聞いたな。","ENG":"I haven't heard that name in a long time.","TWN":"那個名字，好久沒聽到了。"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그 아이 외에는 누구도 나를 그 이름으로 불러주지 않았으니까.","JPN":"あの子を除いては、誰も私のことをその名前で呼んでくれなかったから。","ENG":"Nobody but her would ever call me by that name.","TWN":"除了那孩子，沒人這麼叫過我。"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그리고 그 아이와 다시 만나기 전까지는, 누구도 나를 그 이름으로 부르지 않길 바랬고.","JPN":"それに、あの子にまた会えるまでは、誰にもその名前で呼んでほしくなかった。","ENG":"And until I am reunited with her, I don't wish anyone to call me by that.","TWN":"在再次見到她之前，我希望不會再有人用那個名字稱呼我。"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"그러니까 나를 그 이름으로 부르지 마, 스완.","JPN":"だから私をその名前で呼ぶな、スワン。","ENG":"So, don't you ever say that name again, Swan.","TWN":"所以住口吧，史旺。"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_QM","text":{"KOREA":"지금의 나는 그저 심야의 살인마이자…….","JPN":"今の私は深夜の殺人鬼で……","ENG":"I am now just the Midnight Killer...","TWN":"現在的我只是午夜殺人魔……"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"복수귀, 알레이스터.","JPN":"復讐鬼、アレイスター。","ENG":"The Revenger, Aleister.","TWN":"復仇之鬼，阿萊斯特。"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALEISTER_SWANSONG_NPC_NULL","text":{"KOREA":"그게 내가 이 무대에서 정한 내 배역의 이름이야.","JPN":"それが私がこの舞台で決めた配役の名前だ。","ENG":"That is the name of the role I've given myself for this stage.","TWN":"這是我在這個舞台上為自己定下的角色名。"},"stage":{"bg":"SWANSONG_02","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};